import app from 'flarum/forum/app';
import Page from 'flarum/common/components/Page';
import { mountArmory } from '../armory';

/** The /armory page — a thin Flarum page that mounts the framework-agnostic renderer. */
export default class ArmoryPage extends Page {
  view() {
    return m("div", {
      className: "ArmoryPage"
    }, m("div", {
      className: "container"
    }, m("div", {
      id: "armory-root"
    })));
  }
  oncreate(vnode) {
    super.oncreate(vnode);
    const el = vnode.dom.querySelector('#armory-root');
    if (el) mountArmory(el, app.session.csrfToken || '');
  }
}
flarum.reg.add('ernestdefoe-armory', 'forum/components/ArmoryPage', ArmoryPage);